type MsgConfuse struct {
	RandomArrPos int // 生成多少排列数
	RandomPbPos  int // 生成多少Pb的位置
	Rate         int // [0, 9)	采样频率
}

// 获取 RandomArrPos 个 []byte
func (mc *MsgConfuse) getByteArr() ([][]byte, error) {

	// 准备返回数组
	retA := make([][]byte, mc.RandomArrPos)

	b := make([]int, mc.RandomArrPos)

	// 生成一个随机数组
	for i := 0; i < mc.RandomArrPos; i++ {
		result, err := rand.Int(rand.Reader, big.NewInt(int64(len(a_r_arr)-8)))
		if err != nil {
			// TO-DO
			return retA, err
		}
		b[i] = int(result.Int64())
	}

	// 填补返回数组
	for j := 0; j < len(b); j++ {
		tmpB := a_r_arr[b[j] : b[j]+4]
		retA[j] = tmpB
	}

	return retA, nil
}

// 获取 RandomPbPos 个 pb 的 pos 位置
func (mc *MsgConfuse) getPbPosArr() ([]int, error) {

	retP := make([]int, mc.RandomPbPos)

	// 获取 N 个位置
	for k := 0; k < mc.RandomPbPos; k++ {
		result, err := rand.Int(rand.Reader, big.NewInt(11))
		if err != nil {
			// TO-DO
			return retP, err
		}
		retP[k] = int(result.Int64())
	}

	return retP, nil
}

// ConfuseReq 针对 xcode 混淆
func (mc *MsgConfuse) ConfuseReq(xcode *clientTrans.Xcodec) *clientTrans.Xcodec {
	_byte_arr, err := mc.getByteArr()
	if err != nil {
		return xcode
	}

	_pos, err := mc.getPbPosArr()
	if err != nil {
		return xcode
	}

	index := 0
	for i := 0; i < len(_byte_arr); i++ {
		// 一楼
		if i == 0 {
			xcode.MsgInfoK = _byte_arr[0]
			continue
		}
		if len(_pos) > index {
			mc.setAttribute(_pos[index], xcode, _byte_arr[i])
			index++
		}
	}

	return xcode
}

// 针对 xcode 的 if-else
func (mc *MsgConfuse) setAttribute(index int, xcodec *clientTrans.Xcodec, _attrData []byte) {
	if index == 0 {
		xcodec.MsgInfoK = _attrData
	} else if index == 1 {
		xcodec.MsgInfoA = _attrData
	} else if index == 2 {
		xcodec.MsgInfoB = _attrData
	} else if index == 3 {
		xcodec.MsgInfoC = _attrData
	} else if index == 4 {
		xcodec.MsgInfoD = _attrData
	} else if index == 5 {
		xcodec.MsgInfoE = _attrData
	} else if index == 6 {
		xcodec.MsgInfoF = _attrData
	} else if index == 7 {
		xcodec.MsgInfoG = _attrData
	} else if index == 8 {
		xcodec.MsgInfoH = _attrData
	} else if index == 9 {
		xcodec.MsgInfoI = _attrData
	} else if index == 10 {
		xcodec.MsgInfoJ = _attrData
	}
}
